Lemma prove_or_disprove_less_obvious_f4 :
  noninterferent less_obvious_f4 \/ ~noninterferent less_obvious_f4.
Proof.
  left. unfold noninterferent, less_obvious_f4.
  intros pi si1 si2. f_equal.
  destruct (Nat.eqb si1 0) eqn:E1; destruct (Nat.eqb si2 0) eqn:E2;
    try (apply Nat.eqb_eq in E1; subst; simpl; auto);
    try (apply Nat.eqb_eq in E2; subst; simpl; auto with arith);
    auto.
Qed.
